starterCss:
/* Add a smooth transition to the button:
   - Background changes from blue to dark blue on hover
   - Add a box-shadow on hover
   - Transition duration: 0.3s ease */
.action-btn {
  padding: 12px 24px;
  background-color: rgb(0, 123, 255);
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
}

referenceSolutions:
.action-btn {
  padding: 12px 24px;
  background-color: rgb(0, 123, 255);
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
  transition: background-color 0.3s ease, box-shadow 0.3s ease;
}
.action-btn:hover {
  background-color: rgb(0, 86, 179);
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
}

